/**
 * Specifies the animation settings of the Drawer.
 *
 */
export interface DrawerAnimation {
    /**
     * Specifies the type of the Drawer animation.
     */
    type?: 'slide';
    /**
     * Specifies the duration of the Drawer animation ([see example](components/layout/drawer/display_modes#toc-expand-modes)) .
     */
    duration: number;
}
